156→const CanvasImageNode = ({
157→    canvasImage,
158→    stageWidth,
159→    stageHeight,
160→    isSelected,
161→    isDragging,
162→    onSelect,
163→    onDragStart,
164→    onDragEnd,
165→    canInteract,
166→    preventTouchDefault
167→}) => {
168→    const loadedImage = useLoadedImage(canvasImage?.src);
169→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
170→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
171→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
172→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
173→    const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
174→    const baseScaleX = canvasImage?.scaleX === -1 ? -1 : 1;
175→
176→    return (
177→        <>
178→            <KonvaImage
179→                x={x}
180→                y={y}
181→                width={objectWidth}
182→                height={objectHeight}
183→                image={loadedImage}
184→                draggable={canInteract}
185→                rotation={canvasImage?.rotation || 0}
186→                scaleX={baseScaleX * liftMultiplier}
187→                scaleY={liftMultiplier}
188→                shadowColor="rgba(0,0,0,0.3)"
189→                shadowBlur={isSelected || isDragging ? 16 : 8}
190→                shadowOffsetY={isSelected || isDragging ? 6 : 3}
191→                preventDefault={preventTouchDefault}
192→                onClick={canInteract ? onSelect : undefined}
193→                onTap={canInteract ? onSelect : undefined}
194→                onDragStart={onDragStart}
195→                onDragEnd={onDragEnd}
196→            />
197→            {isSelected && (
198→                <Rect
199→                    x={x}
200→                    y={y}
201→                    width={objectWidth}
202→                    height={objectHeight}
203→                    stroke="#68d391"
204→                    strokeWidth={1.7}
205→                    dash={[6, 4]}
206→                    rotation={canvasImage?.rotation || 0}
207→                    listening={false}
208→                />
209→            )}
210→        </>
211→    );
212→};
